```typescript
import * as pulumi from "@pulumi/pulumi";
import * as ripe_atlas from "@supabase/ripe-atlas";

const dnsCanary = new ripe_atlas.Measurement("dns_canary", {
    name: "dns-canary",
    target: "canary.example.com",
    msmType: "dns",
    af: 4,
    excludeTags: [
        "broken",
        "system-flakey-connection",
    ],
    cohorts: [
        {
            name: "high-freq",
            probeCount: 30,
            maxProbesPerCell: 1,
            intervalSeconds: 60,
            includeProbeIds: [1001],
            excludeProbeIds: [9999],
            cfg: {
                asn: {
                    "7018": 10,
                    "7922": 8,
                },
                tags: {
                    office: 5,
                    fibre: 2,
                },
                stability: {
                    "system-ipv4-stable-90d": 5,
                },
            },
        },
        {
            name: "low-freq",
            probeCount: 100,
            maxProbesPerCell: 2,
            intervalSeconds: 3600,
        },
    ],
});
export const msmIds = dnsCanary.cohorts.apply(cohorts => cohorts.map(c => (c.msmId)));
export const probeIds = dnsCanary.cohorts.apply(cohorts => cohorts.map(c => (c.probeIds)));
